from dataclasses import dataclass, field
from collections import deque
from typing import Optional
import uuid

@dataclass
class Task:
    id: str
    description: str
    priority: int = 5          # 1 (highest) … 10 (lowest)
    depends_on: list[str] = field(default_factory=list)
    result: Optional[str] = None

    @staticmethod
    def create(description: str, priority: int = 5) -> "Task":
        return Task(id=str(uuid.uuid4())[:8], description=description, priority=priority)

class TaskQueue:
    def __init__(self):
        self._tasks: list[Task] = []

    def push(self, task: Task) -> None:
        self._tasks.append(task)
        self._tasks.sort(key=lambda t: t.priority)

    def pop(self) -> Optional[Task]:
        return self._tasks.pop(0) if self._tasks else None

    def is_empty(self) -> bool:
        return len(self._tasks) == 0

    def as_text(self) -> str:
        return "\n".join(
            f"{i+1}. [{t.priority}] {t.description}"
            for i, t in enumerate(self._tasks)
        )

@dataclass
class MemoryStore:
    """Simple in-memory store; replace dict with a vector DB for semantic recall."""
    _entries: dict[str, str] = field(default_factory=dict)

    def store(self, task_id: str, result: str) -> None:
        self._entries[task_id] = result

    def recent(self, n: int = 5) -> str:
        items = list(self._entries.items())[-n:]
        return "\n".join(f"Task {tid}: {res[:200]}" for tid, res in items)

    def all_results(self) -> str:
        return "\n".join(f"Task {tid}: {res}" for tid, res in self._entries.items())

def run_autonomous_agent(
    objective: str,
    seed_tasks: list[str],
    max_iterations: int = 20,
    verbose: bool = True,
) -> dict:
    """Run an AutoGPT/BabyAGI style autonomous agent."""
    queue = TaskQueue()
    memory = MemoryStore()
    completed: list[Task] = []

    # Seed the queue with initial task breakdown
    for i, desc in enumerate(seed_tasks):
        queue.push(Task.create(desc, priority=i + 1))

    for iteration in range(max_iterations):
        if queue.is_empty():
            break

        # ── Execute current task ─────────────────────────────────────────
        task = queue.pop()
        if verbose:
            print(f"\n[{iteration+1}] Executing: {task.description}")

        result = exec_chain.invoke({
            "objective": objective,
            "memory_context": memory.recent(n=5),
            "task_description": task.description,
        })
        task.result = result
        memory.store(task.id, result)
        completed.append(task)

        if verbose:
            print(f"    Result: {result[:120]}...")

        # ── Create new tasks ─────────────────────────────────────────────
        new_tasks_text = create_chain.invoke({
            "objective": objective,
            "completed_task": task.description,
            "result": result,
            "remaining_tasks": queue.as_text() or "(none)",
        })

        if "COMPLETE" in new_tasks_text.upper() and not queue._tasks:
            print("\nObjective achieved.")
            break

        new_descs = parse_task_list(new_tasks_text)
        for desc in new_descs:
            if desc and not any(t.description == desc for t in queue._tasks):
                queue.push(Task.create(desc))

        # ── Re-prioritise ────────────────────────────────────────────────
        if queue._tasks:
            prioritised_text = priority_chain.invoke({
                "objective": objective,
                "tasks": queue.as_text(),
            })
            reprioritised = parse_task_list(prioritised_text)
            # Rebuild queue in new order
            old_map = {t.description: t for t in queue._tasks}
            queue._tasks = []
            for desc in reprioritised:
                if desc in old_map:
                    old_map[desc].priority = reprioritised.index(desc) + 1
                    queue._tasks.append(old_map[desc])

    return {
        "completed_tasks": [t.description for t in completed],
        "results": {t.description: t.result for t in completed},
        "remaining_tasks": [t.description for t in queue._tasks],
    }

# Example run
output = run_autonomous_agent(
    objective="Research the top 3 open-source vector databases and summarise their trade-offs",
    seed_tasks=[
        "List the top open-source vector databases",
        "Research each database's indexing algorithm",
        "Compare query latency benchmarks",
    ],
    max_iterations=15,
)

from typing import TypedDict, Annotated
from langgraph.graph import StateGraph, END
import operator

class AutonomousState(TypedDict):
    objective: str
    task_queue: list[dict]      # serialisable form of Task
    memory: list[str]           # recent results as strings
    completed: list[str]        # completed task descriptions
    iteration: int
    last_result: str

def execute_node(state: AutonomousState) -> AutonomousState:
    if not state["task_queue"]:
        return state
    task = state["task_queue"][0]
    result = exec_chain.invoke({
        "objective": state["objective"],
        "memory_context": "\n".join(state["memory"][-5:]),
        "task_description": task["description"],
    })
    return {
        **state,
        "task_queue": state["task_queue"][1:],
        "memory": state["memory"] + [f"{task['description']}: {result}"],
        "completed": state["completed"] + [task["description"]],
        "last_result": result,
        "iteration": state["iteration"] + 1,
    }

def create_tasks_node(state: AutonomousState) -> AutonomousState:
    if not state["completed"]:
        return state
    new_text = create_chain.invoke({
        "objective": state["objective"],
        "completed_task": state["completed"][-1],
        "result": state["last_result"],
        "remaining_tasks": "\n".join(t["description"] for t in state["task_queue"]) or "(none)",
    })
    if "COMPLETE" in new_text.upper():
        return {**state, "task_queue": []}
    new_descs = parse_task_list(new_text)
    existing = {t["description"] for t in state["task_queue"]}
    new_tasks = [
        {"description": d, "priority": len(state["task_queue"]) + i}
        for i, d in enumerate(new_descs)
        if d and d not in existing
    ]
    return {**state, "task_queue": state["task_queue"] + new_tasks}

def should_continue(state: AutonomousState) -> str:
    if not state["task_queue"]:
        return END
    if state["iteration"] >= 20:
        return END
    return "execute"

graph = StateGraph(AutonomousState)
graph.add_node("execute", execute_node)
graph.add_node("create_tasks", create_tasks_node)
graph.set_entry_point("execute")
graph.add_edge("execute", "create_tasks")
graph.add_conditional_edges("create_tasks", should_continue, {END: END, "execute": "execute"})
app = graph.compile()
